            MultiTransact(
                msg.sender,
                _h,
                m_txs[_h].value,
                m_txs[_h].to,
                m_txs[_h].data,
                created
            );
            delete m_txs[_h];
            return true;
        }
    }

    function confirmAndCheck(bytes32 _operation) internal returns (bool) {
